SELECT id, `쉼표번호`, notification_settings_json, theme, smartwatch_type
FROM user_settings
WHERE `쉼표번호` = #{쉼표번호}

mapper.update:
UPDATE user_settings
SET notification_settings_json = #{notificationSettingsJson},
    theme = #{theme}, smartwatch_type = #{smartwatchType}
WHERE id = #{id}
